mapper.delete:
/* ESS사용량 삭제 */
DELETE FROM tb_ess_usage 
 WHERE ess_usg_idx = #{essUsgIdx}

mapper.select:
/* ESS사용량 전체 개수 조회 */
SELECT COUNT(*) AS CNT
  FROM tb_ess_usage
 WHERE ess_usg_idx = #{essUsgIdx}

/* ESS사용량 상세조회ByUnique */
SELECT ess_usg_idx,
       site_id,
       device_id,
       std_date,
       usg_val,
       reg_date,
       mod_date
  FROM tb_ess_usage
 WHERE site_id = #{siteId}
   AND device_id = #{deviceId}
   AND std_date = #{stdDate}

/* ESS사용량 목록 조회  BySiteId*/
SELECT site_id,
       std_date,
       SUM(usg_val) usg_val
  FROM tb_ess_usage
 WHERE site_id = #{siteId}
   AND std_date BETWEEN #{beginDate} AND #{endDate}
 GROUP BY site_id, std_date
